        LD (BDOS_RETURN_VAL),HL              ; $9C1D  22 45 9F
        ADD HL,SP                        ; $9C20  39
        LD (BDOS_SAVED_SP),HL              ; $9C21  22 0F 9F
        LD SP,FCB_SET_RESULT_CODE_51+2              ; $9C24  31 41 9F
        XOR A                            ; $9C27  AF
        LD ($A9E0),A                     ; $9C28  32 E0 A9
        LD ($A9DE),A                     ; $9C2B  32 DE A9
        LD HL,$A974                      ; $9C2E  21 74 A9
        PUSH HL                          ; $9C31  E5
        LD A,C                           ; $9C32  79
        CP $29                           ; $9C33  FE 29
        RET NC                           ; $9C35  D0
        LD C,E                           ; $9C36  4B
        LD HL,BDOS_DISPATCH_TBL                     ; $9C37  21 47 9C
        LD E,A                           ; $9C3A  5F
        LD D,$00                         ; $9C3B  16 00
        ADD HL,DE                        ; $9C3D  19
        ADD HL,DE                        ; $9C3E  19
        LD E,(HL)                        ; $9C3F  5E
